import{c as s,cG as i,cb as a,c8 as t,cf as e,cT as n,ce as l}from"./chunks/framework.BlkIsu1j.js";const r=JSON.parse('{"title":"Git WorkTree 高效并行开发","description":"","frontmatter":{"title":"Git WorkTree 高效并行开发","categories":"foo","tags":"bar","sidebar":false,"prev":false,"next":false,"comments":false,"date":"2026-04-16T11:40:44.000Z"},"headers":[],"relativePath":"posts/2026/04_16_Git_WorkTree.md","filePath":"posts/2026/04_16_Git_WorkTree.md","lastUpdated":1776322488000}'),h={id:"frontmatter-title",tabindex:"-1"};const k=s({name:"posts/2026/04_16_Git_WorkTree.md"},[["render",function(s,r,k,p,d,o){return i(),a("div",null,[t("h1",h,[e(n(s.$frontmatter.title)+" ",1),r[0]||(r[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),r[1]||(r[1]=l('<h2 id="在日常开发中-你是否遇到过这样的场景" tabindex="-1">在日常开发中，你是否遇到过这样的场景： <a class="header-anchor" href="#在日常开发中-你是否遇到过这样的场景" aria-label="Permalink to “在日常开发中，你是否遇到过这样的场景：”">​</a></h2><ul><li><p>正满头大汗地写着 Feature-A 的重构代码，老板突然说线上有个 Bug 要立刻修？</p></li><li><p>为了对比两个分支的代码，你不得不打开两个不同的 IDE 窗口，甚至手动 clone 了两次代码库？</p></li><li><p>每次切换分支都要 git stash 暂存半成品，等切回来时，甚至忘了当时存了什么？</p><p>如果你的回答是“Yes”，那么 Git Worktree 就是你需要掌握的“真香”神技。</p></li></ul><h2 id="什么是-git-worktree" tabindex="-1">什么是 Git Worktree？ <a class="header-anchor" href="#什么是-git-worktree" aria-label="Permalink to “什么是 Git Worktree？”">​</a></h2><p>在默认情况下，一个 Git 仓库只有一个工作区（Working Tree）。当你执行 git checkout 时，Git 会直接修改你当前目录下的物理文件。 Git Worktree 允许你在同一个仓库中同时拥有多个工作区。 简单理解：它能让你在不同的文件夹里，同时检出（Check out）同一个仓库的不同分支。它们共享同一个 .git 目录和提交历史，但物理路径是完全隔离的。</p><h2 id="核心优势-为什么不用传统的-stash-或-clone" tabindex="-1">核心优势：为什么不用传统的 Stash 或 Clone？ <a class="header-anchor" href="#核心优势-为什么不用传统的-stash-或-clone" aria-label="Permalink to “核心优势：为什么不用传统的 Stash 或 Clone？”">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Git Stash</th><th>Git Clone (副本)</th><th>Git Worktree</th></tr></thead><tbody><tr><td>上下文切换</td><td>必须中断当前工作，保存状态</td><td>需要重新下载代码，耗时耗空间</td><td>秒级切换，互不干扰</td></tr><tr><td>磁盘占用</td><td>极小</td><td>极大（重复的 .git 文件夹）</td><td>极小（共享 .git 目录）</td></tr><tr><td>分支同步</td><td>只能在一个地方看一个分支</td><td>副本间不互通，需要</td><td>fetch 实时同步（共享本地 Ref）</td></tr><tr><td>适用场景</td><td>几分钟的小任务</td><td>隔离环境，长期独立运行</td><td>并行开发、快速热修复、代码对比</td></tr></tbody></table><h2 id="实战场景演示" tabindex="-1">实战场景演示 <a class="header-anchor" href="#实战场景演示" aria-label="Permalink to “实战场景演示”">​</a></h2><ol><li>紧急热修复（Hotfix） 痛点：当前分支改动了 50 个文件，还没法 Commit。 操作： <ol><li>在主项目目录外创建一个新的工作区： <code>git worktree add ../hotfix-branch master</code></li><li>进入 <code>../hotfix-branch</code> 目录，修完 Bug，直接提交并推送到远端。</li><li>删掉该目录，回到原目录继续写你的 <code>Feature-A</code>。你的开发思路完全没被打断。</li></ol></li><li>代码 Review 与 对比 痛点：Review 同事代码时，想在本地跑一下看看效果，但又不想动自己的代码。 操作： 给同事的分支开一个独立的 Worktree，一边看他的代码，一边运行他的程序，而你的编辑器依然保留着你之前的调试断点。</li><li>长耗时编译与测试 痛点：大型项目编译一次要 10 分钟。 操作： 在 Worktree-A 里运行编译脚本，直接切换到 Worktree-B 继续写代码。两个任务物理隔离，互不打架。</li></ol><h2 id="常用命令备忘录" tabindex="-1">常用命令备忘录 <a class="header-anchor" href="#常用命令备忘录" aria-label="Permalink to “常用命令备忘录”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 基于已有分支或commit来checkout</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 语法：git worktree add  &lt;path&gt; [&lt;commit-ish&gt;]</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">${project_name}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">_</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">${branch} ${branch}</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 基于已有分支或commit来创建新分支</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 语法：git worktree add [(-b | -B) &lt;new-branch&gt;] &lt;path&gt; [&lt;commit-ish&gt;]</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ${new_branch} </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">../</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">${project_name}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">_</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">${branch} ${branch}</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看列表</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># worktree目录移动</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> move</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ${worktree_path} ${new-path}</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># worktree 移除(有更改加-f)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [-f] ${worktree_path}</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># worktree prune: 手动删除了worktree，清理无效记录</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prune</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 其它</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># git worktree repair [&lt;path&gt;...]</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># git worktree lock [--reason &lt;string&gt;] &lt;worktree&gt;</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># git worktree unlock &lt;worktree&gt;</span></span></code></pre></div><h2 id="避坑小贴士" tabindex="-1">避坑小贴士 <a class="header-anchor" href="#避坑小贴士" aria-label="Permalink to “避坑小贴士”">​</a></h2><ol><li>禁止“一妻多夫”：Git 不允许两个工作区同时处于同一个分支。如果你想在两个地方操作同一个逻辑，建议给第二个工作区新建一个临时分支（例如 feature-debug）。</li><li>路径建议：建议将 Worktree 目录放在主仓库的上一级（如 ../），这样可以避免 Worktree 目录被主仓库的 Git 误认为是未追踪的文件，也方便清理。</li><li>配置文件：虽然 .git 目录共享，但每个 Worktree 的 index（暂存区）和 HEAD 是独立的，请放心使用。</li></ol><h2 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to “结语”">​</a></h2><p>Git Worktree 改变了我们处理任务优先级的方式。它让我们从“线性工作流”进化到了“并发工作流”。 建议： 下次当你想输入 git stash 的时候，停顿一秒，试着输入一次 git worktree add。相信我，你会爱上这种从容不迫的开发体验。</p>',14))])}]]);export{r as __pageData,k as default};
